function genericRows(field, widgetId = null) {
  const baseRows = widgetId ? rowsThroughReportMonth(widgetId, field) : allRowsSorted().filter(r => r[field] != null);
  return baseRows.map(enrich).filter(r => r && r[field] != null && !Number.isNaN(Number(r[field])));
}
function genericChart(rows, field, type, format) {
  if(!rows.length) return "";
  const percentMode = format === "percent";
  const w = 1120, h = 455, left = 64, right = 120, top = 18, bottom = 52;
  const vals = rows.map(r => r[field]);
  const sc = scale(vals, format !== "percent");
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const xMonth = m => left + (m - 1) * plotW / 11;
  const yVal = v => h - bottom - ((Number(v) - sc.min) / sc.span) * plotH;
  const years = Array.from(new Set(rows.map(r => r.year))).sort();
  const colorMap = {2022:"#a86d74",2023:"#55b85a",2024:"#6b9ac4",2025:"#eab308",2026:"#dc2626"};
  const highlight = rows[rows.length - 1];
  const axisFont = 12.5;

  function axisFmt(v) {
    if(format === "percent") return (Number(v) * 100).toFixed(0) + "%";
    if(Math.abs(v) >= 1000) return Math.round(Number(v)/1000) + "K";
    return Math.round(Number(v)).toString();
  }

  if(type === "bar") {
    const bw = plotW / rows.length;
    const zero = Math.max(sc.min, Math.min(sc.max, 0));
    const base = yVal(zero);
    let svg = `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="xMidYMin meet">`;

    const ticks = 5;
    for(let i = 0; i <= ticks; i++) {
      const val = sc.min + (sc.span * i / ticks);
      const yy = yVal(val);
      svg += `<line class="gridline" x1="${left}" x2="${w-right}" y1="${yy}" y2="${yy}"></line>`;
      svg += `<text class="axis-label" x="${left-12}" y="${yy+6}" text-anchor="end" style="font-size:${axisFont}px">${axisFmt(val)}</text>`;
    }
    svg += `<line class="axis" x1="${left}" x2="${left}" y1="${top}" y2="${h-bottom}"></line>`;
    svg += `<line class="axis" x1="${left}" x2="${w-right}" y1="${base}" y2="${base}"></line>`;

    rows.forEach((r, i) => {
      const x = left + i * bw, y = yVal(r[field]), bh = Math.abs(base - y);
      svg += `<rect class="bar-muted tiptarget" data-tip="${tooltip(['Value','<strong>'+fmt(r[field],format)+'</strong>',r.label])}" x="${x+4}" y="${Math.min(y,base)}" width="${Math.max(4,bw-8)}" height="${Math.max(1,bh)}"></rect>`;
      if(i % Math.ceil(rows.length/10) === 0 || i === rows.length - 1) {
        svg += `<text class="axis-label" x="${x+bw/2}" y="${h-12}" text-anchor="middle" style="font-size:${axisFont}px">${r.month.slice(0,3)} '${String(r.year).slice(2)}</text>`;
      }
    });
    svg += `</svg>`;
    return `<div class="chart short">${svg}</div>`;
  }

  let svg = `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="xMidYMin meet">`;

  const ticks = 5;
  for(let i = 0; i <= ticks; i++) {
    const val = sc.min + (sc.span * i / ticks);
    const yy = yVal(val);
    svg += `<line class="gridline" x1="${left}" x2="${w-right}" y1="${yy}" y2="${yy}"></line>`;
    svg += `<text class="axis-label" x="${left-12}" y="${yy+6}" text-anchor="end" style="font-size:${axisFont}px">${axisFmt(val)}</text>`;
  }
  svg += `<line class="axis" x1="${left}" x2="${left}" y1="${top}" y2="${h-bottom}"></line>`;
  svg += `<line class="axis" x1="${left}" x2="${w-right}" y1="${h-bottom}" y2="${h-bottom}"></line>`;

  for(let m = 1; m <= 12; m++) {
    svg += `<text class="axis-label" x="${xMonth(m)}" y="${h-20}" text-anchor="middle" style="font-size:${axisFont}px">${monthName(m).slice(0,3)}</text>`;
  }

  years.forEach((year, yi) => {
    const pts = rows.filter(r => r.year === year).map(r => [xMonth(monthNum(r.month)), yVal(r[field]), r]);
    const path = pts.map((pt, i) => `${i ? 'L' : 'M'} ${pt[0]} ${pt[1]}`).join(" ");
    const color = colorMap[year] || "#64748b";
    svg += `<path d="${path}" fill="none" stroke="${color}" stroke-width="3.25"></path>`;
    pts.forEach(pt => {
      const isHighlight = highlight && pt[2].year === highlight.year && pt[2].month === highlight.month;
      if(isHighlight){
        svg += `<circle cx="${pt[0]}" cy="${pt[1]}" r="14" fill="none" stroke="#ef4444" stroke-width="2.5" stroke-dasharray="6 5"></circle>`;
      }
      svg += `<circle class="dot tiptarget" data-tip="${tooltip(['Value','<strong>'+fmt(pt[2][field],format)+'</strong>',pt[2].label, 'Year: '+pt[2].year, isHighlight ? 'Current point' : null])}" cx="${pt[0]}" cy="${pt[1]}" r="4.25" style="stroke:${color}"></circle>`;
    });
  });

  years.forEach((year, yi) => {
    const color = colorMap[year] || "#64748b";
    const ly = top + 18 + yi * (percentMode ? 30 : 19);
    svg += `<line x1="${w-right+2}" x2="${w-right+28}" y1="${ly}" y2="${ly}" stroke="${color}" stroke-width="3.25"></line>`;
    svg += `<circle cx="${w-right+15}" cy="${ly}" r="4" fill="#fff" stroke="${color}" stroke-width="2"></circle>`;
    svg += `<text class="legend" x="${w-right+38}" y="${ly+7}" style="font-size:18px;font-weight:900">${year}</text>`;
  });

  svg += `</svg>`;
  return `<div class="chart short">${svg}</div>`;
}


function widgetMonthYearControl(widgetId) {
  const sel = WIDGET_REFS[widgetId] || DEFAULT_REF;
  const monthOptions = MONTHS.map(([name,num]) => `<option value="${num}" ${Number(sel.month)===num ? "selected" : ""}>${name}</option>`).join("");
  const years = Array.from(new Set(DATA.map(r=>r.year))).sort();
  const yearOptions = years.map(y => `<option value="${y}" ${Number(sel.year)===Number(y) ? "selected" : ""}>${y}</option>`).join("");
  return `<div class="widget-control">
    <label>Month</label>
    <select onchange="setWidgetRef('${widgetId}', 'month', this.value)">${monthOptions}</select>
    <select onchange="setWidgetRef('${widgetId}', 'year', this.value)">${yearOptions}</select>
  </div>`;
}

function setWidgetRef(widgetId, key, value) {
  if(!WIDGET_REFS[widgetId]) WIDGET_REFS[widgetId] = {...DEFAULT_REF};
  WIDGET_REFS[widgetId][key] = Number(value);
  localStorage.setItem("pa_widget_refs", JSON.stringify(WIDGET_REFS));
  render();
}

function renderGenericCard(cardId, title, sub, field, format, kpisFn) {
  const card = document.getElementById(cardId);
  const rows = genericRows(field, cardId);
  if(!rows.length) { card.classList.add("hidden"); return false; }
  card.classList.remove("hidden");
  const current = rows[rows.length-1];
  const pref = CHART_PREFS[cardId] || "line";
  card.innerHTML = `
    <div class="card-head">
      <div><h3>${escapeHtml(title)}</h3><div class="card-sub">${escapeHtml(sub)}</div></div>
      <div class="widget-controls">
        <div class="toggle"><button class="${pref==='bar'?'active':''}" onclick="setChart('${cardId}','bar')">Bar chart</button><button class="${pref==='line'?'active':''}" onclick="setChart('${cardId}','line')">Line graph</button></div>
      </div>
    </div>
    ${kpiBlock(kpisFn(current, rows))}
    <div class="context">Summary cards reference <strong>${current.month} ${current.year}</strong>, based on the reporting month.</div>
    ${genericChart(rows, field, pref, format)}
  `;
  return true;
}
function setChart(cardId, type) {
  CHART_PREFS[cardId] = type;
  localStorage.setItem("pa_presentation_chart_prefs", JSON.stringify(CHART_PREFS));
  render();
}

function renderMembership() {
  const ref = enrich(latestActiveRow());
  if(!ref) { document.getElementById("membershipSection").classList.add("hidden"); return; }
  document.getElementById("membershipSection").classList.remove("hidden");
  const annual = annualData(ref);
  const target = targetMonthData(ref);
  const proj = projectionData(ref);
  const prevDec = BY_YEAR_MONTH[(ref.year-1)+"-12"];
  const annualGrowth = prevDec?.activeGolfers ? (ref.activeGolfers-prevDec.activeGolfers)/prevDec.activeGolfers : null;
  const targetLast = target[target.length-1];
  const decProj = proj?.projected?.length ? proj.projected[proj.projected.length-1].value : null;

  const sameMonthPrior = BY_YEAR_MONTH[(ref.year-1) + "-" + monthNum(ref.month)];
  const prevMonthNum = monthNum(ref.month) === 1 ? 12 : monthNum(ref.month) - 1;
  const prevMonthYear = monthNum(ref.month) === 1 ? ref.year - 1 : ref.year;
  const prevMonthRow = BY_YEAR_MONTH[prevMonthYear + "-" + prevMonthNum];

  const relChange = (curr, prior) => (curr != null && prior != null && Number(prior) !== 0) ? (curr - prior) / prior : null;
  const share = (num, denom) => (num != null && denom != null && Number(denom) !== 0) ? num / denom : null;
  const changeMarkup = (change, basisLabel) => {
    if(change == null || !basisLabel) return "";
    const cls = change > 0 ? "positive" : change < 0 ? "negative" : "neutral";
    const arrow = change > 0 ? "▲" : change < 0 ? "▼" : "•";
    return `<div class="dashboard-summary-change ${cls}">${arrow} ${pct(change)} vs ${basisLabel}</div>`;
  };
  const summaryMetric = (label, value, changeHtml, sub) => `
    <div>
      <div class="dashboard-summary-label">${label}</div>
      <div class="dashboard-summary-value">${value}</div>
      ${changeHtml || ""}
      <div class="dashboard-summary-sub">${sub}</div>
    </div>
  `;

  const activeChange = ref.yoyActivePct;
  const newGolfersChange = relChange(ref.newGolfers, sameMonthPrior?.newGolfers);
  const ytdNewGolfersChange = ref.ytdNewPct;
  const onTimeRenewalChange = relChange(ref.onTimeRenewalRate, sameMonthPrior?.onTimeRenewalRate);
  const rollingRetentionChange = relChange(ref.retentionRate, prevMonthRow?.retentionRate);
  const reactivationsChange = relChange(ref.reactivations, sameMonthPrior?.reactivations);
  const recoveryShareChange = relChange(ref.recoveryShare, share(sameMonthPrior?.reactivations, sameMonthPrior?.activeGolfers));

  document.getElementById("membershipHero").innerHTML = `
    <div>
      <div class="summary-strip-top">
        <div class="summary-strip-copy">
          <div class="dashboard-summary-title">Membership Summary</div>
          <p><strong>${fmt(ref.activeGolfers)}</strong> active GC golfers through <strong>${ref.month} ${ref.year}</strong>, with current performance shown across membership, acquisition, retention, and recovery.</p>
        </div>
        <div class="summary-strip-ref">Reporting month: <strong>${ref.month} ${ref.year}</strong></div>
      </div>

      <div class="dashboard-summary-grid">
        <div class="dashboard-summary-group membership">
          <div class="dashboard-summary-group-title">Membership</div>
          <div class="dashboard-summary-metrics">
            ${summaryMetric("Active GC golfers", fmt(ref.activeGolfers), changeMarkup(activeChange, `${ref.month} ${ref.year-1}`), "Current total")}
            ${summaryMetric("Growth so far", fmt(annualGrowth,'percent'), "", `Vs Dec ${ref.year-1}`)}
          </div>
        </div>

        <div class="dashboard-summary-group acquisition">
          <div class="dashboard-summary-group-title">Acquisition</div>
          <div class="dashboard-summary-metrics">
            ${summaryMetric("New golfers", fmt(ref.newGolfers), changeMarkup(newGolfersChange, `${ref.month} ${ref.year-1}`), `${ref.month} ${ref.year}`)}
            ${summaryMetric("YTD new golfers", fmt(ref.ytdNewGolfers), changeMarkup(ytdNewGolfersChange, `Jan–${ref.month} ${ref.year-1}`), `Jan through ${ref.month}`)}
          </div>
          <a class="dashboard-summary-link" onclick="setTab('acquisition')">Open Acquisition →</a>
        </div>

        <div class="dashboard-summary-group retention">
          <div class="dashboard-summary-group-title">Retention</div>
          <div class="dashboard-summary-metrics">
            ${summaryMetric("On-time renewal", fmt(ref.onTimeRenewalRate,'percent'), changeMarkup(onTimeRenewalChange, `${ref.month} ${ref.year-1}`), "Current month")}
            ${summaryMetric("12M retention", fmt(ref.retentionRate,'percent'), changeMarkup(rollingRetentionChange, `${prevMonthRow?.month} ${prevMonthRow?.year}`), "Rolling rate")}
          </div>
          <a class="dashboard-summary-link" onclick="setTab('retention')">Open Retention →</a>
        </div>

        <div class="dashboard-summary-group recovery">
          <div class="dashboard-summary-group-title">Recovery</div>
          <div class="dashboard-summary-metrics">
            ${summaryMetric("Reactivations", fmt(ref.reactivations), changeMarkup(reactivationsChange, `${ref.month} ${ref.year-1}`), `${ref.month} ${ref.year}`)}
            ${summaryMetric("Recovery %", fmt(ref.recoveryShare,'percent'), changeMarkup(recoveryShareChange, `${ref.month} ${ref.year-1}`), "Of active golfers")}
          </div>
          <a class="dashboard-summary-link" onclick="setTab('recovery')">Open Recovery →</a>
        </div>
      </div>
    </div>
  `;

  document.getElementById("annualCard").innerHTML = `
    <div class="card-head">
      <div>
        <h3>Total Membership Growth</h3>
      </div>
    </div>
    <div class="square-exec-top">
      <div class="square-exec-story inline">
        <div class="square-exec-hero">${pct(annualGrowth)}</div>
        <div class="square-exec-chip-label">Growth so far this year</div>
      </div>
    </div>
    <div class="square-exec-copy">
      <strong>${fmt(ref.activeGolfers)}</strong> active GC golfers through <strong>${ref.month} ${ref.year}</strong>, compared with <strong>${fmt(prevDec?.activeGolfers)}</strong> at year-end ${ref.year-1}.
    </div>
    ${executiveMiniBarChart(annual, "Total Membership Growth")}
`;

  normalizeYoyRef();
  const yoyBase = BY_YEAR_MONTH[YOY_REF.year + "-" + YOY_REF.month];
  const yoyRef = enrich(yoyBase);
  const yoyTarget = targetMonthData(yoyRef);
  const isYoyCurrent = rowIdx(yoyRef) === rowIdx(ref);
  const yoyVerb = isYoyCurrent ? "is" : "was";
  const totalVerb = isYoyCurrent ? "is" : "was";
  const totalLabel = isYoyCurrent ? "Current total" : `${yoyRef.month}'s total`;

  document.getElementById("targetMonthCard").innerHTML = `
    <div class="card-head">
      <div>
        <h3>Year Over Year Growth</h3>
        <div class="card-sub">Same month across years, back to 2022.</div>
      </div>
      ${yoyControls()}
    </div>
    <div class="square-exec-top">
      <div class="square-exec-story inline">
        <div class="square-exec-hero">${pct(yoyRef.yoyActivePct)}</div>
        <div class="square-exec-chip-label">Year-over-year growth</div>
      </div>
    </div>
    <div class="square-exec-copy">
      <strong>${yoyRef.month} ${yoyRef.year}</strong> ${yoyVerb} up <strong>${fmt(yoyRef.yoyActiveChange)}</strong> golfers from <strong>${yoyRef.month} ${yoyRef.year-1}</strong>. ${totalLabel} ${totalVerb} <strong>${fmt(yoyRef.activeGolfers)}</strong>.
    </div>
    ${executiveMiniBarChart(yoyTarget, yoyRef.month + " Membership by Year")}
`;

  document.getElementById("projectionCard").innerHTML = `
    <div class="card-head">
      <div>
        <h3>${ref.year} Year-End Projection</h3>
      </div>
    </div>
    <div class="square-exec-top">
      <div class="square-exec-story inline">
        <div class="square-exec-hero" style="color:#1f2937">${fmt(decProj)}</div>
        <div class="square-exec-chip-label">(${pct(proj?.factor ? proj.factor-1 : null,1)} growth) projected by EOY</div>
      </div>
    </div>
    <div class="square-exec-copy">
      Actuals through <strong>${ref.month}</strong>. Current total is <strong>${fmt(ref.activeGolfers)}</strong> versus prior year-end of <strong>${fmt(prevDec?.activeGolfers)}</strong>.
    </div>
    ${projectionChart(proj)}
`;
}

function updateSections() {
  [["acquisitionSection",["newGolfersCard","ytdNewGolfersCard"]],["retentionSection",["renewalCard","retentionCard"]],["recoverySection",["reactivationsCard"]]].forEach(([sectionId,cards]) => {
    const visible = cards.some(id => !document.getElementById(id).classList.contains("hidden"));
    document.getElementById(sectionId).classList.toggle("hidden", !visible);
  });
}
function renderOtherSections() {
  renderGenericCard("newGolfersCard","Monthly New Golfers","New golfers by creation month, shown year over year.","newGolfers","count",
    r => [["New golfers",r.newGolfers,"count"],["Active GC golfers",r.activeGolfers,"count"],["New as % of active",r.newShare,"percent"],["Selected month",r.month+" "+r.year,"text"]]);
  renderGenericCard("ytdNewGolfersCard","Year-to-Date New Golfers","Cumulative new golfers from January through the selected month, shown year over year.","ytdNewGolfers","count",
    r => [["Current YTD",r.ytdNewGolfers,"count"],["Prior-year YTD",r.priorYtdNewGolfers,"count"],["YTD change",r.ytdNewChange,"count"],["YTD % change",r.ytdNewPct,"percent"]]);
  renderGenericCard("renewalCard","On-Time Renewal Rate","Golfers due for renewal who remain active after the renewal month closes.","onTimeRenewalRate","percent",
    r => [["On-time renewal",r.onTimeRenewalRate,"percent"],["Renewed",r.renewed,"count"],["Up for renewal",r.upForRenewal,"count"],["Not renewed",r.notRenewed,"count"]]);
  renderGenericCard("retentionCard","12 Month Rolling Retention Rate","Prior-year active golfers who are still active in the current reporting month.","retentionRate","percent",
    r => [["12M retention",r.retentionRate,"percent"],["Selected month",r.month+" "+r.year,"text"],["Retained golfers",r.retainedGolfers,"count"],["Prior-year active",r.priorYearActiveGolfers,"count"]]);
  renderGenericCard("reactivationsCard","Reactivation Widget","Existing golfers who became active again during the reporting month.","reactivations","count",
    r => [["Reactivations",r.reactivations,"count"],["Active GC golfers",r.activeGolfers,"count"],["Recovery as % of active",r.recoveryShare,"percent"],["Selected month",r.month+" "+r.year,"text"]]);
  updateSections();
}

function renderNote() {
  const ref = latestActiveRow();

}
function render() {
  renderMembership();
  renderOtherSections();
  renderNote();
}
function initControls() {
  // Global date controls removed. Widgets own their reporting-month controls.
}

function setTab(tabName) {
  document.querySelectorAll(".tab-btn").forEach(btn => {
    btn.classList.toggle("active", btn.dataset.tab === tabName);
  });
  document.querySelectorAll(".tab-panel").forEach(panel => {
    panel.classList.toggle("active", panel.id === "tab-" + tabName);
  });
  localStorage.setItem("pa_active_tab", tabName);
}

function initTabs() {
  const saved = localStorage.getItem("pa_active_tab") || "summary";
  setTab(saved);
}

document.addEventListener("mouseover", e => {
  const t = e.target.closest(".tiptarget");
  if(!t) return;
  const tt = document.getElementById("tooltip");
  tt.innerHTML = t.dataset.tip || "";
  tt.style.display = "block";
});
document.addEventListener("mousemove", e => {
  const tt = document.getElementById("tooltip");
  if(tt.style.display === "block") {
    tt.style.left = (e.clientX + 14) + "px";
    tt.style.top = (e.clientY + 14) + "px";
  }
});
document.addEventListener("mouseout", e => {
  if(e.target.closest(".tiptarget")) document.getElementById("tooltip").style.display = "none";
});
initControls();
render();
initTabs();
